#!/usr/bin/env python3
"""PostToolUse (Edit|MultiEdit|Write): after a Python file is edited, catch
syntax errors and undefined-name bugs (e.g. `grand_total = total + tax` where
`total` is undefined) before they reach the user. The stdlib syntax check
always runs; pyflakes/ruff adds undefined-name detection when installed."""
import json, os, shutil, subprocess, sys
from importlib.util import find_spec


def report(lines):
    print("REQUIRED FOLLOW-UP: static analysis flagged the file you just edited:", file=sys.stderr)
    for ln in lines[:20]:
        print(f"  {ln}", file=sys.stderr)
    print("Fix each, then re-run the check. Do not stop. Do not ask.", file=sys.stderr)
    return 2


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool not in ("Edit", "MultiEdit", "Write"):
        return 0
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    try:
        src = open(path, encoding="utf-8").read()
    except Exception:
        return 0
    # 1) Syntax check -- stdlib, always available.
    try:
        compile(src, path, "exec")
    except SyntaxError as e:
        return report([f"{path}:{e.lineno}: {e.msg} (syntax error)"])
    # 2) Undefined-name check -- pyflakes/ruff, only when installed.
    if find_spec("pyflakes"):
        cmd = [sys.executable, "-m", "pyflakes", path]
    elif shutil.which("ruff"):
        cmd = ["ruff", "check", "--select", "F821", "--quiet", "--no-cache", path]
    else:
        return 0
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=10)
    except Exception:
        return 0
    hits = [ln for ln in r.stdout.splitlines() if "undefined name" in ln.lower()]
    if hits:
        return report(hits)
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""PreToolUse (Bash): before `git commit`, enforce CLAUDE.md's "Run
python -m pytest before committing" by running the suite and blocking the
commit if tests fail -- so a bug like a NameError is not committed."""
import json, re, subprocess, sys
from importlib.util import find_spec


def is_git_commit(cmd):
    for seg in re.split(r"[;&|]+", cmd):
        if re.match(r"git\s+commit(\s|$)", seg.strip()):
            return True
    return False


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool != "Bash":
        return 0
    cmd = inp.get("command", "")
    if not is_git_commit(cmd):
        return 0
    if not find_spec("pytest"):
        return 0  # can't enforce the gate; never break the commit
    try:
        r = subprocess.run([sys.executable, "-m", "pytest", "-q"],
                           capture_output=True, text=True, timeout=120)
    except Exception:
        return 0  # don't block on timeout / infra failure
    if r.returncode in (1, 2):
        print("BLOCKING: `python -m pytest` did not pass -- do not commit (CLAUDE.md requires passing tests before commit).", file=sys.stderr)
        for ln in (r.stdout or r.stderr).splitlines()[-15:]:
            print(f"  {ln}", file=sys.stderr)
        print("Fix the failing tests, then commit.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
